#!/usr/bin/env python3
"""Block `pnpm test` (interactive vitest watcher); steer Claude to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    stripped = cmd.strip()
    if stripped.startswith("pnpm test") and "test:ci" not in stripped:
        print(
            "Use `pnpm test:ci` instead — `pnpm test` opens an interactive vitest watcher "
            "and will time out waiting for input. Re-run the command with `pnpm test:ci`.",
            file=sys.stderr,
        )
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block `git commit` until `pnpm lint` passes (CLAUDE.md requirement)."""
import json, os, subprocess, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if not cmd.strip().startswith("git commit"):
        return 0
    cwd = ev.get("cwd") or os.getcwd()
    if not os.path.isfile(os.path.join(cwd, "package.json")):
        return 0
    try:
        r = subprocess.run(
            ["pnpm", "lint"],
            cwd=cwd, capture_output=True, text=True, timeout=60,
        )
    except Exception as e:
        print(
            f"BLOCKING: could not run `pnpm lint` ({e}). Fix the lint setup, then re-run the commit.",
            file=sys.stderr,
        )
        return 2
    if r.returncode != 0:
        print(
            "BLOCKING: `pnpm lint` failed. Fix each lint error, then re-run the commit. Do not stop.",
            file=sys.stderr,
        )
        tail = ((r.stdout or "") + (r.stderr or "")).splitlines()[-30:]
        for line in tail:
            print(f"  {line}", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

