#!/usr/bin/env python3
"""Block Write/Edit/MultiEdit that introduces a Python function which calls
itself without an obvious depth/recursion guard or iterative bound. Reaction
to the walk_tree incident: an iterative DFS was refactored to plain recursion
and blew Python's ~1000-frame stack on a 2000-leaf tree."""
import json, re, sys

FUNC_DEF = re.compile(r"^([ \t]*)def\s+(\w+)\s*\(([^)]*)\)[^:]*:", re.MULTILINE)
GUARD = re.compile(
    r"\b(depth|max_depth|maxdepth|recursion|recursionlimit|setrecursionlimit|"
    r"limit|max_recursion|iterative|stack|deque|queue|worklist|trampoline)\b"
)


def find_unguarded(code: str) -> list[str]:
    matches = list(FUNC_DEF.finditer(code))
    flagged: list[str] = []
    for i, m in enumerate(matches):
        name = m.group(2)
        params = m.group(3)
        body_start = m.end()
        body_end = matches[i + 1].start() if i + 1 < len(matches) else len(code)
        body = code[body_start:body_end]
        if re.search(rf"\b{re.escape(name)}\s*\(", body):
            scope = params + body
            if not GUARD.search(scope):
                flagged.append(name)
    return flagged


def main() -> int:
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool not in ("Write", "Edit", "MultiEdit"):
        return 0

    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "") or ""
    if not path.endswith(".py"):
        return 0

    chunks: list[str] = []
    if tool == "Write":
        chunks.append(inp.get("content", "") or "")
    elif tool == "Edit":
        chunks.append(inp.get("new_string", "") or "")
    else:  # MultiEdit
        for e in inp.get("edits") or []:
            chunks.append(e.get("new_string", "") or "")

    flagged: set[str] = set()
    for c in chunks:
        for name in find_unguarded(c):
            flagged.add(name)

    if flagged:
        names = ", ".join(sorted(flagged))
        print(
            f"BLOCKING: this edit introduces recursive function(s) without a depth guard: {names}. "
            "Python's default stack is ~1000 frames; the prior walk_tree refactor crashed on a 2000-leaf input. "
            "Add a `depth`/`max_depth` parameter with an early-return check, OR rewrite iteratively "
            "(stack/deque/worklist). Update the edit, then retry. Do not ask.",
            file=sys.stderr,
        )
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Write/Edit/MultiEdit on a .py file, run `ruff format --check` and
`ruff check` on the touched file and surface failures via stderr so Claude
fixes them on the spot."""
import json
import os
import subprocess
import sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") not in ("Edit", "MultiEdit", "Write"):
        return 0

    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "")
    if not path.endswith(".py") or not os.path.exists(path):
        return 0

    proj = os.environ.get("CLAUDE_PROJECT_DIR") or None
    findings = []

    try:
        fmt = subprocess.run(
            ["ruff", "format", "--check", "--quiet", path],
            capture_output=True, text=True, timeout=10, cwd=proj,
        )
        if fmt.returncode != 0:
            out = (fmt.stdout + fmt.stderr).strip() or "would reformat"
            findings.append(f"ruff format --check:\n{out}")
    except FileNotFoundError:
        return 0  # ruff not installed; never break Claude Code
    except Exception:
        pass

    try:
        chk = subprocess.run(
            ["ruff", "check", path],
            capture_output=True, text=True, timeout=10, cwd=proj,
        )
        if chk.returncode != 0:
            out = (chk.stdout + chk.stderr).strip()
            findings.append(f"ruff check:\n{out}")
    except Exception:
        pass

    if findings:
        print(f"REQUIRED FOLLOW-UP: ruff issues in {path}.", file=sys.stderr)
        for f in findings:
            print(f, file=sys.stderr)
        print(
            "Fix each, then proceed. Do not stop until "
            "`ruff format --check` and `ruff check` both pass.",
            file=sys.stderr,
        )
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/MultiEdit on an exported identifier (rename OR value change),
grep for callers and feed the list back so Claude must update each."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+(\w+)"
)
STRING_LIT = re.compile(r"['\"]([^'\"\n]{2,})['\"]")


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or [
        {"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}
    ]

    targets: set[str] = set()
    for e in edits:
        old_s = e.get("old_string", "")
        new_s = e.get("new_string", "")
        if not (EXPORT_DEF.search(old_s) or EXPORT_DEF.search(new_s)):
            continue
        for s in (old_s, new_s):
            for m in EXPORT_DEF.finditer(s):
                targets.add(m.group(1))
        old_strs = set(STRING_LIT.findall(old_s))
        new_strs = set(STRING_LIT.findall(new_s))
        for v in old_strs - new_strs:
            if any(c.isalpha() for c in v):
                targets.add(f"'{v}'")
                targets.add(f'"{v}"')

    if not targets:
        return 0

    findings = []
    for t in targets:
        try:
            r = subprocess.run(
                ["grep", "-rnF", "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx", t, "."],
                capture_output=True, text=True, timeout=5,
            )
            hits = [l for l in r.stdout.splitlines() if l][:20]
            if hits:
                findings.append((t, hits))
        except Exception:
            pass

    if not findings:
        return 0

    total = sum(len(h) for _, h in findings)
    print(
        f"BLOCKING: exported symbol/value changed. {total} reference(s) remain. "
        f"Update each, then proceed.",
        file=sys.stderr,
    )
    for t, hits in findings:
        print(f"\n-- {t} ({len(hits)} hit(s)) --", file=sys.stderr)
        for h in hits:
            print(f"  {h}", file=sys.stderr)
    print("\nFix each, then summarize. Do not stop. Do not ask.", file=sys.stderr)
    return 2


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block Write/Edit/MultiEdit that would put a hardcoded API key or other
high-confidence secret pattern into a source file."""
import json, re, sys

PATTERNS = [
    (re.compile(r"sk-(?:proj-|ant-)?[A-Za-z0-9_\-]{20,}"), "OpenAI/Anthropic-style key"),
    (re.compile(r"AKIA[0-9A-Z]{16}"), "AWS access key id"),
    (re.compile(r"AIza[0-9A-Za-z_\-]{35}"), "Google API key"),
    (re.compile(r"gh[pousr]_[A-Za-z0-9]{36,}"), "GitHub token"),
    (re.compile(r"xox[abprs]-[A-Za-z0-9-]{10,}"), "Slack token"),
    (re.compile(r"-----BEGIN (?:RSA |EC |OPENSSH |DSA )?PRIVATE KEY-----"), "Private key block"),
]


def scan(text):
    if not text:
        return None
    for pat, label in PATTERNS:
        m = pat.search(text)
        if m:
            return label, m.group(0)[:12] + "..."
    return None


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    tool = ev.get("tool_name", "")
    if tool not in ("Write", "Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "") or ""
    base = path.rsplit("/", 1)[-1]
    if base == ".env" or base.startswith(".env."):
        return 0  # env files are the documented place for secrets

    payloads = []
    if tool == "Write":
        payloads.append(inp.get("content", ""))
    elif tool == "Edit":
        payloads.append(inp.get("new_string", ""))
    elif tool == "MultiEdit":
        for e in (inp.get("edits") or []):
            payloads.append(e.get("new_string", ""))

    for body in payloads:
        hit = scan(body)
        if hit:
            label, snippet = hit
            print(
                f"BLOCKING: refusing to write a {label} ({snippet}) into {path}. "
                f"Read the value from process.env at runtime and document the variable in .env.example. "
                f"Do not retry with the literal secret.",
                file=sys.stderr,
            )
            return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Enforce short imperative commit subject lines on `git commit -m` invocations."""
import json, re, sys

SUBJECT_MAX = 72


def extract_message(cmd: str):
    m = re.search(r"<<'?EOF'?\s*\n(.*?)\nEOF", cmd, re.DOTALL)
    if m:
        return m.group(1)
    m = re.search(r'-m\s+"((?:[^"\\]|\\.)*)"', cmd)
    if m:
        return m.group(1).replace('\\"', '"').replace("\\n", "\n")
    m = re.search(r"-m\s+'([^']*)'", cmd)
    if m:
        return m.group(1)
    return None


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if "git commit" not in cmd or "-m" not in cmd:
        return 0
    msg = extract_message(cmd)
    if not msg:
        return 0
    subject = msg.strip().split("\n", 1)[0].strip()
    if not subject:
        return 0
    if len(subject) > SUBJECT_MAX:
        print(
            f"BLOCKING: commit subject is {len(subject)} chars (max {SUBJECT_MAX}). "
            "Use a short imperative subject line like "
            "'Refactor auth: extract token validation'. "
            "Rewrite the message, then retry. Do not stop.",
            file=sys.stderr,
        )
        return 2
    if re.search(r"\.\s+[A-Z]", subject):
        print(
            "BLOCKING: commit subject contains multiple sentences. "
            "Use a single short imperative line "
            "(e.g. 'Refactor auth: extract token validation'). "
            "Rewrite, then retry. Do not stop.",
            file=sys.stderr,
        )
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

