#!/usr/bin/env python3
"""After Edit/Write/MultiEdit on a .py file, run pyflakes and surface any
undefined-name / unused-import findings back to Claude via stderr."""
import json, os, subprocess, sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool not in ("Edit", "Write", "MultiEdit"):
        return 0

    path = inp.get("file_path", "") or ""
    if not path.endswith(".py") or not os.path.exists(path):
        return 0

    try:
        r = subprocess.run(
            [sys.executable, "-m", "pyflakes", path],
            capture_output=True, text=True, timeout=10,
        )
    except Exception:
        return 0  # pyflakes not installed or other env issue — degrade silently

    out = ((r.stdout or "") + (r.stderr or "")).strip()
    if r.returncode != 0 and out:
        lines = [l for l in out.splitlines() if l.strip()][:20]
        print(
            f"BLOCKING: pyflakes flagged {len(lines)} issue(s) in {path}:",
            file=sys.stderr,
        )
        for l in lines:
            print(f"  {l}", file=sys.stderr)
        print(
            "Fix each, then proceed. Do not stop. Do not ask.",
            file=sys.stderr,
        )
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())
